mapper.select:
SELECT id, bom_code, materiel_code, materiel_desc, version_number, state, bom_level, lock_status, validity, factory, remark, is_deleted FROM sp_bom WHERE is_deleted = '0' AND lock_status = 'locked' AND validity = '有效'
AND bom_level = #{bomLevel}
AND materiel_code = #{materielCode}
ORDER BY bom_level, materiel_code, version_number DESC
